SELECT ?year WHERE {
  wd:Q334526 wdt:P1346 ?championship .
  ?championship wdt:P585 ?year .
} ORDER BY ?year LIMIT 1

SELECT ?year WHERE {
  ?event wdt:P1343 wd:Q162885 .
  ?event wdt:P545 wd:Q334526 .
  ?event wdt:P585 ?year .
} ORDER BY ASC(?year) LIMIT 1

SELECT ?year WHERE {
  wd:Q334526 p:P1346 ?statement .
  ?statement ps:P1346 wd:Q162885 .
  ?statement pq:P585 ?pointInTime .
  BIND(YEAR(?pointInTime) AS ?year)
} ORDER BY ?year LIMIT 1

